import {
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
} from '@/components/ui/card';
import {
  Table,
  TableBody,
  TableCell,
  TableHead,
  TableHeader,
  TableRow,
} from '@/components/ui/table';
import type { Service } from '@/lib/types';
import { ReactNode } from 'react';

interface PricingTableProps {
    title: string;
    description: string;
    services: Service[];
    subheading?: string;
    footerContent?: ReactNode;
}

export function PricingTable({ title, description, services, subheading, footerContent }: PricingTableProps) {
  const hasHirePurchase = services.some(s => s.hirePrice || s.purchasePrice);

  return (
    <Card>
      <CardHeader>
        <CardTitle>{title}</CardTitle>
        <CardDescription>
          {description}
        </CardDescription>
        {subheading && <h2 className="text-2xl font-headline font-bold text-foreground pt-4">{subheading}</h2>}
      </CardHeader>
      <CardContent className={footerContent ? 'pb-0' : ''}>
        <Table>
          <TableHeader>
            <TableRow>
              <TableHead>Service</TableHead>
              <TableHead>Description</TableHead>
              {hasHirePurchase ? (
                <>
                  <TableHead className="text-right">Hire Price</TableHead>
                  <TableHead className="text-right">Purchase Price</TableHead>
                </>
              ) : (
                <TableHead className="text-right">Price</TableHead>
              )}
            </TableRow>
          </TableHeader>
          <TableBody>
            {services.map((service) => (
              <TableRow key={service.id}>
                <TableCell className="font-medium">{service.name}</TableCell>
                <TableCell className="text-muted-foreground">{service.description}</TableCell>
                {hasHirePurchase ? (
                    <>
                        <TableCell className="text-right">
                            <span className="font-semibold">{service.hirePrice}</span>
                        </TableCell>
                         <TableCell className="text-right">
                            <span className="font-semibold">{service.purchasePrice}</span>
                        </TableCell>
                    </>
                ): (
                    <TableCell className="text-right">
                        <span className="font-semibold">{service.price}</span>
                        {service.unit && <span className="text-sm text-muted-foreground">/{service.unit}</span>}
                    </TableCell>
                )}
              </TableRow>
            ))}
          </TableBody>
        </Table>
      </CardContent>
      {footerContent}
    </Card>
  );
}
